const gsItems  = $('Google Sheets').all();
const eodAll   = $('HTTP Request - EOD').all();
const newsAll  = $('HTTP Request - News').all();

// Helper: handles pairedItem as object, array, or number
function getPairedIdx(item) {
  const pi = item.pairedItem;
  if (pi === null || pi === undefined) return 0;
  if (Array.isArray(pi)) return pi[0]?.item ?? 0;
  if (typeof pi === 'object') return pi.item ?? 0;
  return Number(pi) || 0;
}

// Group split items back by ticker using pairedItem index
const eodByIdx  = {};
const newsByIdx = {};

eodAll.forEach(item => {
  const idx = getPairedIdx(item);
  if (!eodByIdx[idx]) eodByIdx[idx] = [];
  eodByIdx[idx].push(item.json);
});

newsAll.forEach(item => {
  const idx = getPairedIdx(item);
  if (!newsByIdx[idx]) newsByIdx[idx] = [];
  newsByIdx[idx].push(item.json);
});

const oneWeekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const results = [];
const failedTickers = [];

gsItems.forEach((gsItem, idx) => {
  const ticker = (gsItem.json.ticker || '').toString().trim().toUpperCase();
  if (!ticker) return;

  const eodData  = eodByIdx[idx]  || [];
  const newsData = newsByIdx[idx] || [];

  const eodFailed  = eodData.length === 0  || eodData[0]?.error  !== undefined;
  const newsFailed = newsData.length === 0 || newsData[0]?.error !== undefined;

  if (eodFailed && newsFailed) { failedTickers.push(ticker); return; }

  // Price & change
  const sorted = [...eodData].sort((a, b) => new Date(b.date) - new Date(a.date));
  let price = null, changePct = null;
  if (sorted.length >= 2) {
    price = sorted[0].close;
    const prev = sorted[1].close;
    changePct = prev !== 0 ? ((price - prev) / prev) * 100 : null;
  } else if (sorted.length === 1) {
    price = sorted[0].close;
  }

  // News — filter to last 7 days
  const news = newsData
    .filter(a => a.date && new Date(a.date) >= oneWeekAgo)
    .slice(0, 5)
    .map(a => {
      const polarity = a.sentiment?.polarity ?? null;
      const sentimentEmoji  = polarity === null ? '' : polarity > 0.6 ? '😊' : polarity < 0.4 ? '😟' : '😐';
      const sentimentLabel  = polarity === null ? '' : polarity > 0.6 ? 'Positivo' : polarity < 0.4 ? 'Negativo' : 'Neutral';
      const sentimentColor  = polarity === null ? '#718096' : polarity > 0.6 ? '#276749' : polarity < 0.4 ? '#c53030' : '#b7791f';
      return {
        title: a.title || 'Untitled',
        date:  a.date  || '',
        url:   a.link  || a.url || '#',
        summary: (a.content || a.description || '').toString().substring(0, 200),
        tags: (a.tags || []).slice(0, 3),
        sentimentEmoji, sentimentLabel, sentimentColor
      };
    });

  if (eodFailed) failedTickers.push(ticker);
  results.push({ ticker, price, changePct, news, error: eodFailed });
});

// Classify movers
const withChange = results.filter(r => r.changePct !== null);
withChange.sort((a, b) => Math.abs(b.changePct) - Math.abs(a.changePct));

// ── Build HTML ──────────────────────────────────────────────────────────────
const today = new Date().toLocaleDateString('en-US', { weekday:'long', year:'numeric', month:'long', day:'numeric' });
const fmtPrice = v => v != null ? `$${Number(v).toFixed(2)}` : 'N/A';
const fmtPct   = v => v != null ? `${v >= 0 ? '+' : ''}${Number(v).toFixed(2)}%` : 'N/A';
const pctColor = v => v == null ? '#718096' : v >= 0 ? '#276749' : '#c53030';
const signal   = v => v == null ? '⚪' : v >= 2 ? '🟢' : v <= -2 ? '🔴' : '🟡';

// Movers table rows
const moverRows = results.map(r => `
  <tr style='border-top:1px solid #edf2f7;background:transparent;'>
    <td style='padding:11px 12px;font-weight:700;color:#1a202c;'>${r.ticker}</td>
    <td style='padding:11px 12px;text-align:right;color:#2d3748;'>${fmtPrice(r.price)}</td>
    <td style='padding:11px 12px;text-align:right;color:${pctColor(r.changePct)};font-weight:700;'>${fmtPct(r.changePct)}</td>
    <td style='padding:11px 12px;text-align:center;font-size:18px;'>${signal(r.changePct)}</td>
  </tr>`).join('');

// News sections
const newsSections = results.map(r => {
  if (!r.news || r.news.length === 0) return '';
  const articles = r.news.map(a => {
    const tagsHtml = a.tags.length
      ? `<div style='margin-top:5px;'>${a.tags.map(t => `<span style='display:inline-block;background:#edf2f7;color:#4a5568;font-size:10px;padding:2px 7px;border-radius:10px;margin-right:4px;'>${t}</span>`).join('')}</div>`
      : '';
    const sentHtml = a.sentimentLabel
      ? `<span style='font-size:11px;color:${a.sentimentColor};font-weight:600;'>${a.sentimentEmoji} ${a.sentimentLabel}</span>`
      : '';
    return `
    <div style='padding:12px 0;border-bottom:1px solid #f0f2f5;'>
      <div style='display:flex;justify-content:space-between;align-items:flex-start;gap:8px;'>
        <a href='${a.url}' style='font-size:13px;font-weight:600;color:#2b6cb0;text-decoration:none;line-height:1.4;'>${a.title}</a>
        ${sentHtml}
      </div>
      ${a.summary ? `<p style='margin:5px 0 0;font-size:12px;color:#718096;line-height:1.5;'>${a.summary}…</p>` : ''}
      ${tagsHtml}
      <p style='margin:4px 0 0;font-size:11px;color:#a0aec0;'>${a.date ? new Date(a.date).toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'}) : ''}</p>
    </div>`;
  }).join('');

  return `
  <div style='background:#fff;border-radius:10px;padding:22px 26px;margin-bottom:16px;box-shadow:0 1px 5px rgba(0,0,0,.07);'>
    <h3 style='margin:0 0 12px;font-size:15px;font-weight:700;color:#2d3748;'>${r.ticker}</h3>
    ${articles}
  </div>`;
}).join('');

const failedSection = failedTickers.length
  ? `<p style='color:#a0aec0;font-size:12px;text-align:center;'>⚠️ No data for: ${failedTickers.join(', ')}</p>`
  : '';

const html = `<!DOCTYPE html><html lang='en'><head><meta charset='UTF-8'></head>
<body style='font-family:Arial,sans-serif;max-width:700px;margin:0 auto;padding:20px;background:#f0f2f5;'>
<div style='background:linear-gradient(135deg,#1a1a2e,#16213e);color:white;padding:24px 28px;border-radius:10px;margin-bottom:24px;'>
  <h1 style='margin:0;font-size:22px;font-weight:700;'>📊 Daily Market Digest</h1>
  <p style='margin:8px 0 0;color:#90aec6;font-size:13px;'>${today}</p>
</div>
<div style='background:#fff;border-radius:10px;padding:22px 26px;margin-bottom:24px;box-shadow:0 1px 5px rgba(0,0,0,.07);'>
  <h2 style='margin:0 0 18px;font-size:16px;font-weight:700;color:#2d3748;border-bottom:2px solid #e8ecf0;padding-bottom:12px;'>📈 Top Movers</h2>
  <table style='width:100%;border-collapse:collapse;font-size:14px;'>
    <thead><tr style='background:#f7f9fc;'>
      <th style='padding:9px 12px;text-align:left;color:#718096;font-size:11px;text-transform:uppercase;'>Ticker</th>
      <th style='padding:9px 12px;text-align:right;color:#718096;font-size:11px;text-transform:uppercase;'>Last Close</th>
      <th style='padding:9px 12px;text-align:right;color:#718096;font-size:11px;text-transform:uppercase;'>Change %</th>
      <th style='padding:9px 12px;text-align:center;color:#718096;font-size:11px;text-transform:uppercase;'>Signal</th>
    </tr></thead>
    <tbody>${moverRows}</tbody>
  </table>
</div>
<div style='background:#fff;border-radius:10px;padding:22px 26px;margin-bottom:24px;box-shadow:0 1px 5px rgba(0,0,0,.07);'>
  <h2 style='margin:0 0 18px;font-size:16px;font-weight:700;color:#2d3748;border-bottom:2px solid #e8ecf0;padding-bottom:12px;'>📰 News — Last 7 Days</h2>
  ${newsSections || '<p style="color:#a0aec0;font-size:13px;">No news found for the selected period.</p>'}
</div>
${failedSection}
<p style='text-align:center;color:#a0aec0;font-size:11px;margin-top:8px;'>Generated by n8n · Data by EODHD</p>
</body></html>`;

return [{
  json: {
    html,
    subject: `📊 Daily Market Digest — ${new Date().toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})}`
  }
}];
